mapper.update:
update project
set state = 1
where id = #{id}

update project
set spider = #{spider}
where id = #{id}

mapper.select:
SELECT v.principal as name, wu.ratio
FROM volume v
left join workday_user wu on FIND_IN_SET(wu.`user`,REPLACE ( v.principal, ";", "," )) and wu.project_id = #{id}
WHERE v.project_id = #{id}

SELECT pid, projectName, general, id, number, volumeName, dep, tec, state, principal, designer, checker, start_date, planned_shot_date, shot_date, proofreading_date, planned_publication_date, actual_publication_date, complete_time, workday_state, workday, `grant`, reason, TRUE AS hasChildren FROM ( SELECT DISTINCT p.id AS pid, p.NAME AS projectName, p.general, v.id AS id, v.number, v.`name` AS volumeName, v.dep, v.tec, v.state as state, v.principal, v.designer, v.checker, v.start_date, v.planned_shot_date, v.shot_date, v.proofreading_date, v.planned_publication_date, v.actual_publication_date, v.complete_time, w.state as workday_state, w.workday, h.`grant`, s.reason FROM project p, volume v LEFT JOIN volume_workday w on v.id = w.volume_id left join volume_workday_high h on v.id = h.volume_id left join volume_reason s on v.id = s.volume_id WHERE v.project_id = p.id AND ( FIND_IN_SET(#{name}, REPLACE ( v.principal, ";", "," )) OR v.designer = #{name} OR v.checker = #{name} OR p.general = #{name})
GROUP BY SUBSTRING_INDEX( v.number, "+", 1 ) ) AS dataTable WHERE ( start_date >= #{queryStart}
AND start_date <= #{queryEnd})
OR ( planned_shot_date >= #{queryStart}
AND planned_shot_date <= #{queryEnd})
OR ( proofreading_date >= #{queryStart}
AND proofreading_date <= #{queryEnd})
OR ( shot_date >= #{queryStart}
AND shot_date <= #{queryEnd})
OR ( complete_time >= #{queryStart}
AND complete_time <= #{queryEnd})
OR ( planned_publication_date >= #{queryStart}
AND planned_publication_date <= #{queryEnd})
OR ( actual_publication_date >= #{queryStart}
AND actual_publication_date <= #{queryEnd})
GROUP BY `number`

SELECT DISTINCT
    ifnull(SUM(b.workday),0)
FROM
    `user` u,
    workday_backup_user b
WHERE
    u.id = #{userId}
  AND b.issuer_id = u.id
  AND b.date = #{map.date}
and b.project_id = #{map.id}
